class SecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final long TIMESTAMP_VALIDITY_MILLIS = 5 * 60 * 1000;
    private static final Set<String> processedMessageIds = Collections.newSetFromMap(new ConcurrentHashMap<>());

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        
        if (outbound) {
            return handleOutboundMessage(context);
        } else {
            return handleInboundMessage(context);
        }
    }

    private boolean handleOutboundMessage(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();
            
            if (header == null) {
                header = envelope.addHeader();
            }
            
            addSecurityHeader(header);
            message.saveChanges();
            
            return true;
        } catch (Exception e) {
            throw new RuntimeException("Error adding security header: " + e.getMessage(), e);
        }
    }

    private boolean handleInboundMessage(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();
            
            if (header == null) {
                throw new SecurityException("Missing SOAP header");
            }
            
            validateSecurityHeader(header);
            
            return true;
        } catch (SecurityException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException("Error validating security header: " + e.getMessage(), e);
        }
    }

    private void addSecurityHeader(SOAPHeader header) throws SOAPException {
        SOAPElement security = header.addChildElement("Security", "wsse", WSSE_NS);
        security.addNamespaceDeclaration("wsu", WSU_NS);
        
        SOAPElement timestamp = security.addChildElement("Timestamp", "wsu", WSU_NS);
        String messageId = UUID.randomUUID().toString();
        timestamp.addAttribute(new QName(WSU_NS, "Id", "wsu"), "TS-" + messageId);
        
        Date now = new Date();
        Date expires = new Date(now.getTime() + TIMESTAMP_VALIDITY_MILLIS);
        
        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        dateFormat.setTimeZone(TimeZone.getTimeZone("UTC"));
        
        SOAPElement created = timestamp.addChildElement("Created", "wsu", WSU_NS);
        created.setTextContent(dateFormat.format(now));
        
        SOAPElement expiresElement = timestamp.addChildElement("Expires", "wsu", WSU_NS);
        expiresElement.setTextContent(dateFormat.format(expires));
    }

    private void validateSecurityHeader(SOAPHeader header) throws Exception {
        Iterator<?> securityElements = header.getChildElements(new QName(WSSE_NS, "Security"));
        
        if (!securityElements.hasNext()) {
            throw new SecurityException("Missing Security header");
        }
        
        SOAPElement security = (SOAPElement) securityElements.next();
        Iterator<?> timestampElements = security.getChildElements(new QName(WSU_NS, "Timestamp"));
        
        if (!timestampElements.hasNext()) {
            throw new SecurityException("Missing Timestamp in Security header");
        }
        
        SOAPElement timestamp = (SOAPElement) timestampElements.next();
        validateTimestamp(timestamp);
    }

    private void validateTimestamp(SOAPElement timestamp) throws Exception {
        String messageId = timestamp.getAttributeValue(new QName(WSU_NS, "Id"));
        
        if (messageId != null && !messageId.isEmpty()) {
            if (processedMessageIds.contains(messageId)) {
                throw new SecurityException("Replay attack detected: Message ID already processed");
            }
        }
        
        Iterator<?> createdElements = timestamp.getChildElements(new QName(WSU_NS, "Created"));
        Iterator<?> expiresElements = timestamp.getChildElements(new QName(WSU_NS, "Expires"));
        
        if (!createdElements.hasNext()) {
            throw new SecurityException("Missing Created timestamp");
        }
        
        SOAPElement created = (SOAPElement) createdElements.next();
        String createdValue = created.getTextContent();
        
        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        dateFormat.setTimeZone(TimeZone.getTimeZone("UTC"));
        
        Date createdDate = dateFormat.parse(createdValue);
        Date now = new Date();
        
        if (createdDate.after(now)) {
            throw new SecurityException("Timestamp created date is in the future");
        }
        
        long timeDiff = now.getTime() - createdDate.getTime();
        if (timeDiff > TIMESTAMP_VALIDITY_MILLIS) {
            throw new SecurityException("Timestamp has expired (created too long ago)");
        }
        
        if (expiresElements.hasNext()) {
            SOAPElement expires = (SOAPElement) expiresElements.next();
            String expiresValue = expires.getTextContent();
            Date expiresDate = dateFormat.parse(expiresValue);
            
            if (now.after(expiresDate)) {
                throw new SecurityException("Timestamp has expired");
            }
            
            if (createdDate.after(expiresDate)) {
                throw new SecurityException("Invalid timestamp: Created date is after Expires date");
            }
        }
        
        if (messageId != null && !messageId.isEmpty()) {
            processedMessageIds.add(messageId);
            scheduleMessageIdCleanup(messageId);
        }
    }

    private void scheduleMessageIdCleanup(String messageId) {
        Timer timer = new Timer(true);
        timer.schedule(new TimerTask() {
            @Override
            public void run() {
                processedMessageIds.remove(messageId);
            }
        }, TIMESTAMP_VALIDITY_MILLIS * 2);
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSSE_NS, "Security"));
        return headers;
    }
}

